BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?container ?containerName ?stmt ?stmtType WHERE {
  ?container vocab:NamedElement_name ?containerName .
  FILTER(CONTAINS(LCASE(STR(?containerName)), LCASE("aps"))) .
  {
    ?container vocab:Element_ownedComment+ ?comment .
    ?comment vocab:Comment_body ?stmt .
  }
  UNION
  {
    ?container vocab:ownedComment+ ?comment .
    ?comment vocab:Comment_body ?stmt .
  }
  UNION
  {
    ?container vocab:body ?stmt .
  }
  BIND("body/comment" AS ?stmtType)
  FILTER(CONTAINS(LCASE(STR(?stmt)), "stake"))
  BIND(?container AS ?container)
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?apsElem ?apsName ?text WHERE {
  ?apsElem vocab:NamedElement_name ?apsName .
  FILTER(CONTAINS(LCASE(STR(?apsName)), LCASE("aps")))

  { 
    ?apsElem vocab:ownedComment+ ?comment .
    ?comment rdf:type vocab:comment .
    ?comment vocab:Comment_body ?text .
  }
  UNION
  {
    ?apsElem rdf:type vocab:comment .
    ?apsElem vocab:Comment_body ?text .
  }
  UNION
  {
    ?apsElem vocab:body ?text .
  }

  FILTER(CONTAINS(LCASE(STR(?text)), "stake"))
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?dependency ?depName ?client ?clientName ?supplier ?supplierName WHERE {
  ?dependency rdf:type vocab:dependency .
  OPTIONAL { ?dependency vocab:NamedElement_name ?depName . }
  OPTIONAL { ?dependency vocab:Dependency_client ?client . }
  OPTIONAL { ?dependency vocab:Dependency_supplier ?supplier . }

  {
    ?dependency vocab:NamedElement_name ?depName2 .
    FILTER(CONTAINS(LCASE(STR(?depName2)), LCASE("aps")))
  }
  UNION
  {
    ?client vocab:NamedElement_name ?clientName2 .
    FILTER(CONTAINS(LCASE(STR(?clientName2)), LCASE("aps")))
  }
  UNION
  {
    ?supplier vocab:NamedElement_name ?supplierName2 .
    FILTER(CONTAINS(LCASE(STR(?supplierName2)), LCASE("aps")))
  }

  OPTIONAL { ?client vocab:NamedElement_name ?clientName . }
  OPTIONAL { ?supplier vocab:NamedElement_name ?supplierName . }

  FILTER(BOUND(?client) && BOUND(?supplier))
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?apsElemName ?depName ?clientName ?supplierName WHERE {
  {
    ?apsElem rdf:type ?apsElemType .
    ?apsElem vocab:NamedElement_name ?apsElemName .
    FILTER(CONTAINS(LCASE(STR(?apsElemName)), LCASE("aps")))
    {
      ?dep rdf:type vocab:dependency .
      ?dep vocab:Dependency_supplier ?apsElem .
    }
  }
  UNION
  {
    ?apsElem rdf:type ?apsElemType .
    ?apsElem vocab:NamedElement_name ?apsElemName .
    FILTER(CONTAINS(LCASE(STR(?apsElemName)), LCASE("aps")))
    {
      ?dep rdf:type vocab:dependency .
      ?dep vocab:Dependency_client ?apsElem .
    }
  }

  OPTIONAL { ?dep vocab:NamedElement_name ?depName . }
  OPTIONAL { ?dep vocab:Dependency_client ?client . }
  OPTIONAL { ?dep vocab:Dependency_supplier ?supplier . }
  OPTIONAL { ?client vocab:NamedElement_name ?clientName . }
  OPTIONAL { ?supplier vocab:NamedElement_name ?supplierName . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?stake ?stakeName ?rel ?relName WHERE {
  ?apsRoot vocab:NamedElement_name ?apsName .
  FILTER(CONTAINS(LCASE(STR(?apsName)), LCASE("APS%20Mission")) || CONTAINS(LCASE(STR(?apsName)), LCASE("APS Mission")) || CONTAINS(LCASE(STR(?apsName)), LCASE("APS%20")) )

  ?apsRoot vocab:Element_ownedElement+ ?sub .
  {
    ?sub rdf:type vocab:dependency .
    ?sub vocab:Dependency_client ?stake .
    OPTIONAL { ?sub vocab:NamedElement_name ?relName . }
    BIND(?sub AS ?rel)
  }
  UNION
  {
    ?sub rdf:type vocab:dependency .
    ?sub vocab:Dependency_supplier ?stake .
    OPTIONAL { ?sub vocab:NamedElement_name ?relName . }
    BIND(?sub AS ?rel)
  }

  OPTIONAL { ?stake vocab:NamedElement_name ?stakeName . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?stake ?stakeName (COUNT(*) as ?count) WHERE {
  ?apsRoot vocab:NamedElement_name ?apsName .
  FILTER(CONTAINS(LCASE(STR(?apsName)), LCASE("aps%20mission")) || CONTAINS(LCASE(STR(?apsName)), LCASE("aps%20")))

  ?apsRoot vocab:Element_ownedElement+ ?depRel .
  ?depRel rdf:type vocab:dependency .

  {
    ?depRel vocab:Dependency_client ?stake .
  }
  UNION
  {
    ?depRel vocab:Dependency_supplier ?stake .
  }

  OPTIONAL { ?stake vocab:NamedElement_name ?stakeName . }
  FILTER(!CONTAINS(LCASE(STR(?stakeName)), LCASE("aps")))
}
GROUP BY ?stake ?stakeName
ORDER BY DESC(?count)
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?relType ?stake ?stakeName WHERE {
  ?apsRoot vocab:NamedElement_name ?apsName .
  FILTER(CONTAINS(LCASE(STR(?apsName)), LCASE("APS%20Mission")) || CONTAINS(LCASE(STR(?apsName)), LCASE("APS%20")))

  ?apsRoot vocab:Element_ownedElement+ ?relNode .

  {
    ?relNode rdf:type ?relType .
    FILTER(?relType IN (vocab:dependency, vocab:satisfy, vocab:verify, vocab:allocate))

    ?relNode vocab:Dependency_client ?stake .
  }
  UNION
  {
    ?relNode rdf:type ?relType .
    FILTER(?relType IN (vocab:dependency, vocab:satisfy, vocab:verify, vocab:allocate))

    ?relNode vocab:Dependency_supplier ?stake .
  }
  OPTIONAL { ?stake vocab:NamedElement_name ?stakeName . }
}
LIMIT 25
